import React, { useState, useEffect } from 'react';
import { BrowserRouter as Router, Routes, Route, Link } from 'react-router-dom';

// Pages Import
import Home from './pages/Home';
import Services from './pages/Services';
import Registration from './pages/Registration';
import Login from './pages/Login'; 
import AdminDashboard from './pages/Admin'; // ✅ FIXED: Capital 'A'
import ClientDashboard from './pages/ClientDashboard';

// Bootstrap CSS
import 'bootstrap/dist/css/bootstrap.min.css';
import Contact from './pages/Contact'; // 1. Add this import


function App() {
  const [user, setUser] = useState(null);

  useEffect(() => {
    const loggedInUser = localStorage.getItem('clientUser');
    if (loggedInUser) {
      setUser(JSON.parse(loggedInUser));
    }
  }, []);

  const handleLogout = () => {
    localStorage.removeItem('clientUser');
    setUser(null);
    alert("Logged out successfully!");
    window.location.href = "/"; 
  };

  return (
    <Router>
      <div className="App d-flex flex-column min-vh-100 bg-light">
        
        {/* Navigation Bar */}
        <nav className="navbar navbar-expand-lg navbar-dark bg-dark shadow sticky-top py-3">
          <div className="container">
            <Link className="navbar-brand fw-bold fs-3" to="/">
              Freelancer<span className="text-primary"> Marketplace</span>
            </Link>
            
            <button className="navbar-toggler border-0" type="button" data-bs-toggle="collapse" data-bs-target="#navbarNav">
              <span className="navbar-toggler-icon"></span>
            </button>
            
            <div className="collapse navbar-collapse" id="navbarNav">
              <ul className="navbar-nav ms-auto align-items-center gap-2 gap-lg-4">
                <li className="nav-item"><Link className="nav-link text-white px-2" to="/">Home</Link></li>
                <li className="nav-item"><Link className="nav-link text-white px-2" to="/services">Services</Link></li>
                <li className="nav-item"><Link className="nav-link text-info fw-semibold px-2" to="/client-dashboard">Dashboard</Link></li>
                <li className="nav-item border-end pe-lg-3 border-secondary">
                  <Link className="nav-link text-warning fw-semibold px-2" to="/admin">Admin</Link>
                </li>
                
                {!user ? (
                  <>
                    <li className="nav-item"><Link className="nav-link text-white fw-bold px-2" to="/login">Login</Link></li>
                    <li className="nav-item">
                      <Link className="btn btn-primary px-4 rounded-pill shadow-sm fw-bold border-0" to="/register">Hire Me</Link>
                    </li>
                  </>
                ) : (
                  <li className="nav-item">
                    <button onClick={handleLogout} className="btn btn-danger px-4 rounded-pill shadow-sm fw-bold border-0">Logout</button>
                  </li>
                )}
              </ul>
            </div>
          </div>
        </nav>

        <main className="flex-grow-1">
          <Routes>
            <Route path="/" element={<Home />} />
            <Route path="/services" element={<Services />} />
            <Route path="/register" element={<Registration />} />
            <Route path="/login" element={<Login />} />
            <Route path="/admin" element={<AdminDashboard />} />
            <Route path="/client-dashboard" element={<ClientDashboard />} />
            <Route path="/contact" element={<Contact />} /> 
          </Routes>
        </main>

        <footer className="bg-dark text-white py-5 text-center mt-auto border-top border-secondary">
          <div className="container">
            <h5 className="fw-bold mb-3">Freelancer<span className="text-primary"> Marketplace</span></h5>
            <p className="mb-0 x-small opacity-25">© 2026 Freelancer Marketplace</p>
          </div>
        </footer>
      </div>
    </Router>
  );
}

export default App;
